var p={name:"artisan",description:"Laravel Artisan Command",generateSpec:async(c,s)=>{var{stdout:o}=await s({command:"php",args:["artisan","list","--format=json"]});let i=[];try{JSON.parse(o).commands.filter(n=>n.name!=="_complete").map(n=>{i.push({name:n.name,description:n.description,icon:"https://web.tinkerwell.app/img/laravel.3cab6a56.png",args:Object.keys(n.definition.arguments).map(t=>{let e=n.definition.arguments[t];return{name:e.name,description:e.description,isOptional:!e.is_required}}),options:Object.keys(n.definition.options).map(t=>{let e=n.definition.options[t],a=[e.name];return e.shortcut!==""&&a.push(e.shortcut),{name:a,description:e.description}})})})}catch{}return{name:"artisan",debounce:!0,subcommands:i}}},m=p;export{m as default};
